type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: unknown[];
};

type ScenarioResult = {
  results: unknown[];
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results = (scenario.steps as Array<{ op: string; items: Array<{ type: string }> }>).map((step) => {
    const item = step.items[0];
    const basePremium = BASE_PREMIUMS[item.type];
    const premium = Math.ceil(basePremium * 1.10) + 5;
    return { premium };
  });
  return { results };
};

