import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quoting a premium", () => {
    it("should quote a single sword for a new customer on their first contract", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("should quote other main item types (amulet, staff, potion) with correct base premiums", () => {
      const amuletResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }] }],
      });
      expect(amuletResult).toEqual({ results: [{ premium: 71 }] });

      const staffResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 1, cursed: false }] }],
      });
      expect(staffResult).toEqual({ results: [{ premium: 93 }] });

      const potionResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
      });
      expect(potionResult).toEqual({ results: [{ premium: 49 }] });
    });
    it("should quote a single component at 25 G base premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [{ type: "rune", material: "stone", enchantment: 0, cursed: false }],
          },
        ],
      });
      // base 25 + ceil(25 * 0.10) = 25 + 3 = 28 + 5 fee = 33
      expect(result).toEqual({ results: [{ premium: 33 }] });
    });
    it("should apply a special 60 G base premium for a triple of the same component", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // triple component: special base 60 G + ceil(60 * 0.10) = 66 G + 5 fee = 71
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it.todo("should add a 50 % risk surcharge for a cursed item");
    it.todo("should add a 30 % risk surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("should apply a 20 % loyalty discount for a long-standing customer (>= 2 years)");
    it.todo("should apply 10 % initial assessment surcharge on a customer's first contract and 15 % discount on subsequent contracts");
    it.todo("should quote multiple items and sum their premiums with a single 5 G processing fee");
  });

  describe("processing a claim", () => {
    it.todo("should deduct 100 G deductible from damage and return payout and remainingCap");
    it.todo("should cap total payout at twice the insurance sum across multiple claims");
    it.todo("should reimburse at 50 % of damage for items with enchantment level >= 8");
    it.todo("should reimburse 100 % of damage for items made of dragon material");
  });
});

type Item = { type: string };

type QuoteStep = { op: "quote"; items: Item[] };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};

type ScenarioResult = {
  results: unknown[];
};

const COMPONENT_BASE_PREMIUM = 25;
const TRIPLE_COMPONENT_BASE_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    const item = step.items[0];
    const isTripleComponent =
      step.items.length === 3 &&
      step.items.every((i) => i.type === item.type) &&
      !(item.type in BASE_PREMIUMS);
    const basePremium = isTripleComponent ? TRIPLE_COMPONENT_BASE_PREMIUM : (BASE_PREMIUMS[item.type] ?? COMPONENT_BASE_PREMIUM);
    const premium = basePremium + Math.ceil(basePremium * 0.10) + 5;
    return { premium };
  });
  return { results };
};

