        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 1, cursed: false }] }],
      });
      expect(staffResult).toEqual({ results: [{ premium: 93 }] });

